+function withSummaryHeaders(
+  model: NonNullable<ExtensionContext["model"]>,
+  headers?: Record<string, string>,
+): NonNullable<ExtensionContext["model"]> {
+  if (!headers || Object.keys(headers).length === 0) {
+    return model;
+  }
+  return {
+    ...model,
+    headers: {
+      ...model.headers,
+      ...headers,
+    },
+  };
+}
